module AStarHeuristic (  
    input [7:0] current_cost,  
    input [7:0] estimated_cost,  
    output [7:0] total_estimated_cost  
);  
      wire _n01 = current_cost[0] ^ estimated_cost[0];
  wire _c01 = current_cost[0] & estimated_cost[0];
  wire _n02 = current_cost[1] ^ estimated_cost[1] ^ _c01;
  wire _c02 = (current_cost[1] & estimated_cost[1]) | (current_cost[1] & _c01) | (estimated_cost[1] & _c01);
  wire _n03 = current_cost[2] ^ estimated_cost[2] ^ _c02;
  wire _c03 = (current_cost[2] & estimated_cost[2]) | (current_cost[2] & _c02) | (estimated_cost[2] & _c02);
  wire _n04 = current_cost[3] ^ estimated_cost[3] ^ _c03;
  wire _c04 = (current_cost[3] & estimated_cost[3]) | (current_cost[3] & _c03) | (estimated_cost[3] & _c03);
  assign total_estimated_cost = {_n01, _n02, _n03, _n04};  
endmodule
